steps.solution:
def safe_int(text):
    try:
        return int(text)
    except ValueError:
        return 0

print(safe_int("42"))
print(safe_int("hello"))

catalog = {"apple": 2, "bread": 5}

def total(item, qty_text):
    try:
        price = catalog[item]
        qty = int(qty_text)
        return price * qty
    except (KeyError, ValueError):
        return "invalid"

print(total("apple", "10"))
print(total("steak", "10"))
print(total("apple", "ten"))

