def parse_record(data, key):
    try:
        return int(data[key])
    except (KeyError, ValueError) as err:
        print(f"could not parse {key!r}: {type(err).__name__}")
        return None

print(parse_record({"age": "42"}, "age"))
print(parse_record({"age": "n/a"}, "age"))
print(parse_record({"age": "42"}, "name"))

